div.script:
(function() {
    var modalNodes = document.querySelectorAll('.consent_mgmt_modal');
    for (var i = 0; i < modalNodes.length; i++) {
        var modalNode = modalNodes[i];
        if (modalNode && modalNode.parentNode !== document.body) {
            document.body.appendChild(modalNode);
        }
    }
})();
